#ifdef __cplusplus
extern "C" {
#endif

#include <math.h>
#include <omp.h>

#define fp float

#define NUMBER_PAR_PER_BOX 100							
#define NUMBER_THREADS 128								

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))	

typedef struct
{
	fp x, y, z;

} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;

} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;

} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;

	int nn;
	nei_str nei[26];

} box_str;

typedef struct par_str
{
	fp alpha;

} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;

} dim_str;


void kernel_cpu(par_str d_par_cpu,
                dim_str d_dim_cpu,
                box_str *d_box_cpu,
                FOUR_VECTOR *d_rv_cpu,
                fp *d_qv_cpu,
                FOUR_VECTOR *d_fv_cpu)
{
    int bx, tx, wtx;

    #pragma omp parallel private(bx, tx, wtx)
    {
        // Shared arrays per thread team (simulated local memory)
        FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
        FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
        fp qB_shared[NUMBER_PAR_PER_BOX];

        int tid = omp_get_thread_num();
        int nthreads = omp_get_num_threads();

        #pragma omp for schedule(static)
        for (bx = 0; bx < d_dim_cpu.number_boxes; bx++) {

            fp a2 = 2 * d_par_cpu.alpha * d_par_cpu.alpha;

            int first_i = (int)d_box_cpu[bx].offset;

            // Load rA_shared with particles of box bx
            for (wtx = tid; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
                rA_shared[wtx] = d_rv_cpu[first_i + wtx];
            }

            #pragma omp barrier

            for (int k = 0; k < (1 + d_box_cpu[bx].nn); k++) {
                int pointer;
                if (k == 0) {
                    pointer = bx;
                } else {
                    pointer = d_box_cpu[bx].nei[k - 1].number;
                }

                int first_j = (int)d_box_cpu[pointer].offset;

                // Load rB_shared and qB_shared with particles of neighbor box
                for (wtx = tid; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
                    rB_shared[wtx] = d_rv_cpu[first_j + wtx];
                    qB_shared[wtx] = d_qv_cpu[first_j + wtx];
                }

                #pragma omp barrier

                for (wtx = tid; wtx < NUMBER_PAR_PER_BOX; wtx += nthreads) {
                    for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                        fp r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]);
                        fp u2 = a2 * r2;
                        fp vij = expf(-u2);
                        fp fs = 2 * vij;
                        THREE_VECTOR d_vec;
                        d_vec.x = rA_shared[wtx].x - rB_shared[j].x;
                        fp fxij = fs * d_vec.x;
                        d_vec.y = rA_shared[wtx].y - rB_shared[j].y;
                        fp fyij = fs * d_vec.y;
                        d_vec.z = rA_shared[wtx].z - rB_shared[j].z;
                        fp fzij = fs * d_vec.z;

                        // Accumulate results atomically to avoid race conditions
                        #pragma omp atomic
                        d_fv_cpu[first_i + wtx].v += qB_shared[j] * vij;
                        #pragma omp atomic
                        d_fv_cpu[first_i + wtx].x += qB_shared[j] * fxij;
                        #pragma omp atomic
                        d_fv_cpu[first_i + wtx].y += qB_shared[j] * fyij;
                        #pragma omp atomic
                        d_fv_cpu[first_i + wtx].z += qB_shared[j] * fzij;
                    }
                }

                #pragma omp barrier
            }
        }
    }
}

void 
kernel_gpu_opencl_wrapper(	par_str par_cpu,
							dim_str dim_cpu,
							box_str* box_cpu,
							FOUR_VECTOR* rv_cpu,
							fp* qv_cpu,
							FOUR_VECTOR* fv_cpu)
{
    kernel_cpu(par_cpu, dim_cpu, box_cpu, rv_cpu, qv_cpu, fv_cpu);
}

#ifdef __cplusplus
}
#endif
